// Build chunk_text strings from the ingestion payload.
// Each chunk = one question × assignment_type group.
// Prepend proportionality context so it's embedded in the vector.

const INJECTION_PATTERNS = [
  /ignore\s+(all\s+)?(previous|prior|above)\s+(instructions?|prompts?|context)/gi,
  /you\s+are\s+now\s+/gi,
  /\bsystem\s*:/gi,
  /\bassistant\s*:/gi,
  /<\/?(?:system|assistant|user|prompt|instruction)[^>]*>/gi,
];

function sanitize(text) {
  let s = String(text).trim();
  for (const p of INJECTION_PATTERNS) s = s.replace(p, '[removed]');
  return s.replace(/\s+/g, ' ').trim();
}

const LABELS = { peer:'peer', upward:'direct report', downward:'manager', self:'self' };

function label(type) { return LABELS[type] ?? type; }

const payload = $input.item.json;
const cycleId = $('Webhook — Cycle Published').item.json.cycle_id;
const recipientId = payload.recipient?.id;
const chunks = [];

// Text chunks
for (const g of payload.question_groups ?? []) {
  if (!g.comments?.length) continue;
  const l = label(g.assignment_type);
  const prop = `${g.giver_count} of ${g.total_givers} ${l}${g.total_givers !== 1 ? 's' : ''} responded`;
  const lines = g.comments.map(c => `- ${sanitize(c)}`).join('\n');
  chunks.push({
    cycle_id: cycleId,
    recipient_id: recipientId,
    question_id: g.question_id,
    category: g.category ?? 'General',
    assignment_type: g.assignment_type,
    giver_count: g.giver_count,
    total_givers: g.total_givers,
    chunk_text: `Question: ${g.question_text}\nRespondent group: ${l} (${prop}):\n${lines}`,
  });
}

// Ratings chunks grouped by assignment_type × category
const ratingMap = {};
for (const r of payload.ratings ?? []) {
  const key = `${r.assignment_type}::${r.category ?? 'General'}`;
  (ratingMap[key] ??= []).push(r);
}
for (const [key, rows] of Object.entries(ratingMap)) {
  const [at, cat] = key.split('::');
  const totalGivers = Math.max(...rows.map(r => r.total_givers));
  const lines = rows.map(r => `  ${r.question_text}: avg ${r.avg_score}/5 (${r.response_count} ratings)`).join('\n');
  chunks.push({
    cycle_id: cycleId,
    recipient_id: recipientId,
    question_id: null,
    category: cat,
    assignment_type: `${at}_ratings`,
    giver_count: totalGivers,
    total_givers: totalGivers,
    chunk_text: `Numeric ratings — ${cat} — from ${label(at)}s (${totalGivers} respondents):\n${lines}`,
  });
}

return chunks.map(c => ({ json: c }));

// Assemble the generation context from all chunks for this recipient.
// Groups chunks by assignment_type for structured presentation.

const chunks = $input.all().map(i => i.json);
if (!chunks.length) return [{ json: { skip: true } }];

const recipientName = $('Loop over recipients').item.json._recipient_name ?? 'the employee';
const jobTitle      = $('Loop over recipients').item.json._job_title ?? 'Employee';

const TYPE_LABEL = {
  peer:              'PEER FEEDBACK (colleagues at the same level)',
  upward:            'UPWARD FEEDBACK (from direct reports)',
  downward:          'DOWNWARD FEEDBACK (from manager)',
  self:              'SELF-ASSESSMENT',
  peer_ratings:      'PEER NUMERIC RATINGS',
  upward_ratings:    'UPWARD NUMERIC RATINGS (from direct reports)',
  downward_ratings:  'DOWNWARD NUMERIC RATINGS (from manager)',
  self_ratings:      'SELF NUMERIC RATINGS',
};
const ORDER = Object.keys(TYPE_LABEL);

const groups = {};
for (const c of chunks) {
  (groups[c.assignment_type] ??= []).push(c.chunk_text);
}

const sorted = ORDER.filter(t => groups[t])
  .concat(Object.keys(groups).filter(t => !ORDER.includes(t)));

const sections = [
  `Recipient: ${recipientName} — ${jobTitle}`,
  '',
  'You are summarizing 360° feedback collected for this person.',
  'All feedback text below is anonymized (givers are not identified).',
  '',
  '<feedback_context>',
];

for (const type of sorted) {
  sections.push(`\n── ${TYPE_LABEL[type] ?? type.toUpperCase()} ──`);
  for (const text of groups[type]) sections.push(`\n${text}`);
}

sections.push('</feedback_context>');
sections.push('');
sections.push('Generate the summary JSON following the rules in the system prompt.');

return [{ json: { user_message: sections.join('\n') } }];

const raw = $input.item.json.content?.[0]?.text ?? '';
const cleaned = raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { ...parsed, _raw: raw } }];
} catch(e) {
  return [{ json: { _parse_error: e.message, _raw: raw.slice(0,500) } }];
}

